import type React from "react"

interface SectionProps {
  id: string
  label: string
  title: string
  children: React.ReactNode
}

/** A consistently-styled, anchorable content section. */
const Section = ({ id, label, title, children }: SectionProps) => (
  <section id={id} className="border-t border-slate-800/70">
    <div className="mx-auto max-w-5xl px-5 py-20 sm:py-24">
      <header className="mb-10">
        <p className="font-mono text-sm text-primary">{label}</p>
        <h2 className="mt-2 text-3xl font-bold tracking-tight text-white sm:text-4xl">
          {title}
        </h2>
      </header>
      {children}
    </div>
  </section>
)

export default Section

export const Chip = ({ children }: { children: React.ReactNode }) => (
  <span className="rounded-full border border-slate-800 bg-slate-900 px-3 py-1 text-sm text-slate-300 transition hover:border-primary/60 hover:text-white">
    {children}
  </span>
)

export const Card = ({
  children,
  className = "",
}: {
  children: React.ReactNode
  className?: string
}) => (
  <div
    className={`rounded-2xl border border-slate-800 bg-slate-900/60 p-6 transition hover:border-primary/40 ${className}`}
  >
    {children}
  </div>
)
