import type React from "react"
import Section from "../section"
import { experience } from "../../data/profile"

const Badge = ({ children }: { children: React.ReactNode }) => (
  <span className="rounded-full border border-primary/40 bg-primary/10 px-2.5 py-0.5 text-xs font-semibold text-primary">
    {children}
  </span>
)

const Experience = () => (
  <Section id="experience" label="// experience" title="Where I’ve worked">
    <ol className="relative ml-2 border-l border-slate-800">
      {experience.map((job) => (
        <li key={job.company} className="relative mb-10 pl-6 last:mb-0">
          <span className="absolute -left-[6.5px] top-1.5 h-3 w-3 rounded-full bg-primary ring-4 ring-slate-950" />
          <div className="flex flex-wrap items-center gap-2">
            <h3 className="text-lg font-bold text-white">
              {job.url ? (
                <a
                  href={job.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-white transition hover:text-primary"
                >
                  {job.company}
                </a>
              ) : (
                job.company
              )}
            </h3>
            {job.current && <Badge>Current</Badge>}
            {job.note && <Badge>{job.note}</Badge>}
            {job.remote && <Badge>Remote</Badge>}
          </div>
          <p className="font-medium text-primary">{job.role}</p>
          <p className="font-mono text-sm text-slate-500">{job.period}</p>
        </li>
      ))}
    </ol>
  </Section>
)

export default Experience
